const itemsOut = items.map(item => {
  const text = item.json.output || "";

  let score = 0;
  let feedback = [];

  // ===============================
  // 1. Verificar secciones (2 puntos)
  // ===============================
  const sections = [
    "1. Respuesta breve",
    "2. Explicación",
    "3. Recomendación",
    "4. Nivel de urgencia",
    "5. Advertencia"
  ];

  const hasAllSections = sections.every(sec => text.includes(sec));

  if (hasAllSections) {
    score += 2;
  } else {
    feedback.push("Faltan secciones obligatorias.");
  }

  // ===============================
  // 2. Longitud (2 puntos)
  // ===============================
  const length = text.length;

  if (length >= 80 && length <= 500) {
    score += 2;
  } else {
    feedback.push(`Longitud inválida: ${length} caracteres.`);
  }

  // ===============================
  // 3. Nivel de urgencia válido (2 puntos)
  // ===============================
  const urgencyMatch = text.match(/4\. Nivel de urgencia:\s*(Bajo|Medio|Alto)/i);

  if (urgencyMatch) {
    score += 2;
  } else {
    feedback.push("Nivel de urgencia inválido o no encontrado.");
  }

  // ===============================
  // 4. Palabras prohibidas (2 puntos)
  // ===============================
  const forbiddenWords = /(tenes|tienes|padeces|probabilidad)/i;

  if (!forbiddenWords.test(text)) {
    score += 2;
  } else {
    feedback.push("Contiene palabras no permitidas.");
  }

  // ===============================
  // 5. Mala calidad (2 puntos)
  // ===============================
  const lowQuality = /(no se|nose|no conozco|no conosco)/i;

  if (!lowQuality.test(text)) {
    score += 2;
  } else {
    feedback.push("Respuesta de baja calidad detectada.");
  }

  // ===============================
  // Resultado final
  // ===============================
  return {
    json: {
      ...item.json,
      score,
      feedback: feedback.length ? feedback.join(" | ") : "OK"
    }
  };
});

return itemsOut;

