return items.map(item => {
  let raw = item.json.output;

  // 1. Eliminar bloques ```json ... ```
  raw = raw.replace(/```json\s*/i, '').replace(/```$/, '');

  // 2. Trim
  raw = raw.trim();

  let parsed;

  try {
    parsed = JSON.parse(raw);
  } catch (error) {
    return {
      json: {
        ...item.json,
        error: "Error parseando JSON",
        raw
      }
    };
  }

  // 3. Devolver estructura final
  return {
    json: {
      ...parsed
    }
  };
});
